BEGIN TRANSACTION;

IF (SELECT quantite_stock FROM livres WHERE id_livre = 10) >= 3 THEN
    INSERT INTO ventes (id_livre, quantite_vendue, date_vente)
    VALUES (10, 3, CURRENT_DATE);

    UPDATE livres 
    SET quantite_stock = quantite_stock - 3
    WHERE id_livre = 10;

    COMMIT;
ELSE
    ROLLBACK;
END IF;
